using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "which", "who", "whom", "these", "those", "be",
        "been", "being", "have", "has", "had", "do", "does", "did", "will",
        "would", "could", "should", "may", "might", "shall", "can", "need",
        "not", "so", "if", "then", "than", "too", "very", "just", "about",
        "as", "into", "through", "during", "before", "after", "above",
        "below", "between", "each", "every", "all", "both", "few", "more",
        "most", "other", "some", "such", "no", "nor", "only", "own", "same"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(text);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitIntoSentences(string text)
    {
        return SentenceSplitRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(string text)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var word in WordTokenRegex().Matches(text).Select(m => m.Value))
        {
            if (word.Length < 2 || StopWords.Contains(word))
                continue;

            frequencies.TryGetValue(word, out int count);
            frequencies[word] = count + 1;
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = WordTokenRegex().Matches(sentence).Select(m => m.Value).ToList();
        if (words.Count == 0) return 0;

        double score = words
            .Where(w => wordFrequencies.ContainsKey(w))
            .Sum(w => wordFrequencies[w]);

        return score / words.Count;
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordTokenRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

